add("binary-search", "arr1_int", "binary_search", "int", {
    "go": "lo, hi := 0, len(nums)-1\nresult := int64(-1)\nfor lo <= hi {\n\tmid := (lo + hi) / 2\n\tif nums[mid] == extra { result = int64(mid); break }\n\tif nums[mid] < extra { lo = mid + 1 } else { hi = mid - 1 }\n}",
    "ruby": "lo = 0\nhi = nums.length - 1\nresult = -1\nwhile lo <= hi\n  mid = (lo + hi) / 2\n  if nums[mid] == extra\n    result = mid\n    break\n  elsif nums[mid] < extra\n    lo = mid + 1\n  else\n    hi = mid - 1\n  end\nend",
    "kotlin": "var lo = 0\nvar hi = nums.size - 1\nvar result = -1L\nwhile (lo <= hi) {\n    val mid = (lo + hi) / 2\n    if (nums[mid] == extra) { result = mid.toLong(); break }\n    if (nums[mid] < extra) lo = mid + 1 else hi = mid - 1\n}",
    "php": "$lo = 0; $hi = count($nums) - 1; $result = -1;\nwhile ($lo <= $hi) {\n    $mid = intdiv($lo + $hi, 2);\n    if ($nums[$mid] == $extra) { $result = $mid; break; }\n    if ($nums[$mid] < $extra) { $lo = $mid + 1; } else { $hi = $mid - 1; }\n}",
    "scala": "var lo = 0\nvar hi = nums.length - 1\nvar result: Long = -1L\nvar found = false\nwhile (lo <= hi && !found) {\n  val mid = (lo + hi) / 2\n  if (nums(mid) == extra) { result = mid.toLong; found = true }\n  else if (nums(mid) < extra) lo = mid + 1\n  else hi = mid - 1\n}",
    "r": "lo <- 1; hi <- length(nums); result <- -1\nwhile (lo <= hi) {\n  mid <- (lo + hi) %/% 2\n  if (nums[mid] == extra) { result <- mid - 1; break }\n  else if (nums[mid] < extra) { lo <- mid + 1 } else { hi <- mid - 1 }\n}",
    "javascript": "let lo = 0, hi = nums.length - 1;\nlet result = -1;\nwhile (lo <= hi) {\n    const mid = (lo + hi) >> 1;\n    if (nums[mid] === extra) { result = mid; break; }\n    if (nums[mid] < extra) lo = mid + 1; else hi = mid - 1;\n}",
    "typescript": "let lo = 0, hi = nums.length - 1;\nlet result = -1;\nwhile (lo <= hi) {\n    const mid = (lo + hi) >> 1;\n    if (nums[mid] === extra) { result = mid; break; }\n    if (nums[mid] < extra) lo = mid + 1; else hi = mid - 1;\n}",
    "perl": "my $lo = 0; my $hi = scalar(@{$nums}) - 1; my $result = -1;\nwhile ($lo <= $hi) {\n    my $mid = int(($lo + $hi) / 2);\n    if ($nums->[$mid] == $extra) { $result = $mid; last; }\n    if ($nums->[$mid] < $extra) { $lo = $mid + 1; } else { $hi = $mid - 1; }\n}",
    "java": "int lo = 0, hi = nums.length - 1;\nint result = -1;\nwhile (lo <= hi) {\n    int mid = (lo + hi) / 2;\n    if (nums[mid] == extra) { result = mid; break; }\n    if (nums[mid] < extra) lo = mid + 1; else hi = mid - 1;\n}",
    "cpp": "int lo = 0, hi = (int) nums.size() - 1;\nint result = -1;\nwhile (lo <= hi) {\n    int mid = (lo + hi) / 2;\n    if (nums[mid] == extra) { result = mid; break; }\n    if (nums[mid] < extra) lo = mid + 1; else hi = mid - 1;\n}",
    "csharp": "int lo = 0, hi = nums.Length - 1;\nint result = -1;\nwhile (lo <= hi) {\n    int mid = (lo + hi) / 2;\n    if (nums[mid] == extra) { result = mid; break; }\n    if (nums[mid] < extra) lo = mid + 1; else hi = mid - 1;\n}",
    "c": "int lo = 0, hi = n - 1;\nint result = -1;\nwhile (lo <= hi) {\n    int mid = (lo + hi) / 2;\n    if (nums[mid] == extra) { result = mid; break; }\n    if (nums[mid] < extra) lo = mid + 1; else hi = mid - 1;\n}",
    "rust": "let mut lo: i32 = 0;\nlet mut hi: i32 = nums.len() as i32 - 1;\nlet mut result: i32 = -1;\nwhile lo <= hi {\n    let mid = (lo + hi) / 2;\n    if nums[mid as usize] == extra { result = mid; break; }\n    if nums[mid as usize] < extra { lo = mid + 1; } else { hi = mid - 1; }\n}",
    "swift": "var lo = 0\nvar hi = nums.count - 1\nvar result = -1\nwhile lo <= hi {\n    let mid = (lo + hi) / 2\n    if nums[mid] == extra { result = mid; break }\n    if nums[mid] < extra { lo = mid + 1 } else { hi = mid - 1 }\n}",
})


