add("interpolation-search", "arr1_int", "interpolation_search", "int", {
    "go": ("lo, hi := 0, len(nums)-1\nresult := int64(-1)\nfor lo <= hi && extra >= nums[lo] && extra <= nums[hi] {\n\tif nums[hi] == nums[lo] {\n\t\tif nums[lo] == extra { result = int64(lo) }\n\t\tbreak\n\t}\n\tpos := lo + ((extra-nums[lo])*(hi-lo))/(nums[hi]-nums[lo])\n\tif pos < lo || pos > hi { break }\n\tif nums[pos] == extra { result = int64(pos); break }\n\tif nums[pos] < extra { lo = pos + 1 } else { hi = pos - 1 }\n}"),
    "ruby": ("lo = 0\nhi = nums.length - 1\nresult = -1\nwhile lo <= hi && extra >= nums[lo] && extra <= nums[hi]\n  if nums[hi] == nums[lo]\n    result = lo if nums[lo] == extra\n    break\n  end\n  pos = lo + ((extra - nums[lo]) * (hi - lo)) / (nums[hi] - nums[lo])\n  break if pos < lo || pos > hi\n  if nums[pos] == extra\n    result = pos\n    break\n  elsif nums[pos] < extra\n    lo = pos + 1\n  else\n    hi = pos - 1\n  end\nend"),
    "kotlin": ("var lo = 0\nvar hi = nums.size - 1\nvar result = -1L\nwhile (lo <= hi && extra >= nums[lo] && extra <= nums[hi]) {\n    if (nums[hi] == nums[lo]) {\n        if (nums[lo] == extra) result = lo.toLong()\n        break\n    }\n    val pos = lo + ((extra - nums[lo]) * (hi - lo)) / (nums[hi] - nums[lo])\n    if (pos < lo || pos > hi) break\n    if (nums[pos] == extra) { result = pos.toLong(); break }\n    if (nums[pos] < extra) lo = pos + 1 else hi = pos - 1\n}"),
    "php": ("$lo = 0; $hi = count($nums) - 1; $result = -1;\nwhile ($lo <= $hi && $extra >= $nums[$lo] && $extra <= $nums[$hi]) {\n    if ($nums[$hi] == $nums[$lo]) {\n        if ($nums[$lo] == $extra) { $result = $lo; }\n        break;\n    }\n    $pos = $lo + intdiv(($extra - $nums[$lo]) * ($hi - $lo), $nums[$hi] - $nums[$lo]);\n    if ($pos < $lo || $pos > $hi) { break; }\n    if ($nums[$pos] == $extra) { $result = $pos; break; }\n    if ($nums[$pos] < $extra) { $lo = $pos + 1; } else { $hi = $pos - 1; }\n}"),
    "scala": ("var lo = 0\nvar hi = nums.length - 1\nvar result: Long = -1L\nvar stop = false\nwhile (lo <= hi && extra >= nums(lo) && extra <= nums(hi) && !stop) {\n  if (nums(hi) == nums(lo)) {\n    if (nums(lo) == extra) result = lo.toLong\n    stop = true\n  } else {\n    val pos = lo + ((extra - nums(lo)) * (hi - lo)) / (nums(hi) - nums(lo))\n    if (pos < lo || pos > hi) { stop = true }\n    else if (nums(pos) == extra) { result = pos.toLong; stop = true }\n    else if (nums(pos) < extra) lo = pos + 1\n    else hi = pos - 1\n  }\n}"),
    "r": ("lo <- 1; hi <- length(nums); result <- -1\nwhile (lo <= hi && extra >= nums[lo] && extra <= nums[hi]) {\n  if (nums[hi] == nums[lo]) {\n    if (nums[lo] == extra) result <- lo - 1\n    break\n  }\n  pos <- lo + ((extra - nums[lo]) * (hi - lo)) %/% (nums[hi] - nums[lo])\n  if (pos < lo || pos > hi) break\n  if (nums[pos] == extra) { result <- pos - 1; break }\n  else if (nums[pos] < extra) { lo <- pos + 1 } else { hi <- pos - 1 }\n}"),
    "javascript": ("let lo = 0, hi = nums.length - 1;\nlet result = -1;\nwhile (lo <= hi && extra >= nums[lo] && extra <= nums[hi]) {\n  if (nums[hi] === nums[lo]) { if (nums[lo] === extra) result = lo; break; }\n  const pos = lo + Math.floor(((extra - nums[lo]) * (hi - lo)) / (nums[hi] - nums[lo]));\n  if (pos < lo || pos > hi) break;\n  if (nums[pos] === extra) { result = pos; break; }\n  if (nums[pos] < extra) lo = pos + 1; else hi = pos - 1;\n}"),
    "typescript": ("let lo = 0, hi = nums.length - 1;\nlet result = -1;\nwhile (lo <= hi && extra >= nums[lo] && extra <= nums[hi]) {\n  if (nums[hi] === nums[lo]) { if (nums[lo] === extra) result = lo; break; }\n  const pos = lo + Math.floor(((extra - nums[lo]) * (hi - lo)) / (nums[hi] - nums[lo]));\n  if (pos < lo || pos > hi) break;\n  if (nums[pos] === extra) { result = pos; break; }\n  if (nums[pos] < extra) lo = pos + 1; else hi = pos - 1;\n}"),
    "perl": ("my $lo = 0; my $hi = scalar(@{$nums}) - 1; my $result = -1;\nwhile ($lo <= $hi && $extra >= $nums->[$lo] && $extra <= $nums->[$hi]) {\n  if ($nums->[$hi] == $nums->[$lo]) { if ($nums->[$lo] == $extra) { $result = $lo; } last; }\n  my $pos = $lo + int((($extra - $nums->[$lo]) * ($hi - $lo)) / ($nums->[$hi] - $nums->[$lo]));\n  last if $pos < $lo || $pos > $hi;\n  if ($nums->[$pos] == $extra) { $result = $pos; last; }\n  if ($nums->[$pos] < $extra) { $lo = $pos + 1; } else { $hi = $pos - 1; }\n}"),
    "java": ("int lo = 0, hi = nums.length - 1;\nint result = -1;\nwhile (lo <= hi && extra >= nums[lo] && extra <= nums[hi]) {\n  if (nums[hi] == nums[lo]) { if (nums[lo] == extra) result = lo; break; }\n  int pos = lo + ((extra - nums[lo]) * (hi - lo)) / (nums[hi] - nums[lo]);\n  if (pos < lo || pos > hi) break;\n  if (nums[pos] == extra) { result = pos; break; }\n  if (nums[pos] < extra) lo = pos + 1; else hi = pos - 1;\n}"),
    "cpp": ("int lo = 0, hi = (int) nums.size() - 1;\nint result = -1;\nwhile (lo <= hi && extra >= nums[lo] && extra <= nums[hi]) {\n  if (nums[hi] == nums[lo]) { if (nums[lo] == extra) result = lo; break; }\n  int pos = lo + ((extra - nums[lo]) * (hi - lo)) / (nums[hi] - nums[lo]);\n  if (pos < lo || pos > hi) break;\n  if (nums[pos] == extra) { result = pos; break; }\n  if (nums[pos] < extra) lo = pos + 1; else hi = pos - 1;\n}"),
    "csharp": ("int lo = 0, hi = nums.Length - 1;\nint result = -1;\nwhile (lo <= hi && extra >= nums[lo] && extra <= nums[hi]) {\n  if (nums[hi] == nums[lo]) { if (nums[lo] == extra) result = lo; break; }\n  int pos = lo + ((extra - nums[lo]) * (hi - lo)) / (nums[hi] - nums[lo]);\n  if (pos < lo || pos > hi) break;\n  if (nums[pos] == extra) { result = pos; break; }\n  if (nums[pos] < extra) lo = pos + 1; else hi = pos - 1;\n}"),
    "c": ("int lo = 0, hi = n - 1;\nint result = -1;\nwhile (lo <= hi && extra >= nums[lo] && extra <= nums[hi]) {\n  if (nums[hi] == nums[lo]) { if (nums[lo] == extra) result = lo; break; }\n  int pos = lo + ((extra - nums[lo]) * (hi - lo)) / (nums[hi] - nums[lo]);\n  if (pos < lo || pos > hi) break;\n  if (nums[pos] == extra) { result = pos; break; }\n  if (nums[pos] < extra) lo = pos + 1; else hi = pos - 1;\n}"),
    "rust": ("let mut lo: i32 = 0;\nlet mut hi: i32 = nums.len() as i32 - 1;\nlet mut result: i32 = -1;\nwhile lo <= hi && extra >= nums[lo as usize] && extra <= nums[hi as usize] {\n  if nums[hi as usize] == nums[lo as usize] {\n    if nums[lo as usize] == extra { result = lo; }\n    break;\n  }\n  let pos = lo + ((extra - nums[lo as usize]) * (hi - lo)) / (nums[hi as usize] - nums[lo as usize]);\n  if pos < lo || pos > hi { break; }\n  if nums[pos as usize] == extra { result = pos; break; }\n  if nums[pos as usize] < extra { lo = pos + 1; } else { hi = pos - 1; }\n}"),
    "swift": ("var lo = 0\nvar hi = nums.count - 1\nvar result = -1\nwhile lo <= hi && extra >= nums[lo] && extra <= nums[hi] {\n  if nums[hi] == nums[lo] { if nums[lo] == extra { result = lo }; break }\n  let pos = lo + ((extra - nums[lo]) * (hi - lo)) / (nums[hi] - nums[lo])\n  if pos < lo || pos > hi { break }\n  if nums[pos] == extra { result = pos; break }\n  if nums[pos] < extra { lo = pos + 1 } else { hi = pos - 1 }\n}"),
})

