# ═════════════════════════════════════════════════════════════════════════
add("fibonacci-search", "arr1_int", "fibonacci_search", "int", {
    "go": ("n := len(nums)\nresult := int64(-1)\nfibMMm2 := 0\nfibMMm1 := 1\nfibM := fibMMm2 + fibMMm1\nfor fibM < n {\n\tfibMMm2 = fibMMm1\n\tfibMMm1 = fibM\n\tfibM = fibMMm2 + fibMMm1\n}\noffset := -1\nfor fibM > 1 {\n\ti := offset + fibMMm2\n\tif i < n-1 { i = i } else { i = n - 1 }\n\tif i < 0 { i = 0 }\n\tif nums[i] < extra {\n\t\tfibM = fibMMm1\n\t\tfibMMm1 = fibMMm2\n\t\tfibMMm2 = fibM - fibMMm1\n\t\toffset = i\n\t} else if nums[i] > extra {\n\t\tfibM = fibMMm2\n\t\tfibMMm1 = fibMMm1 - fibMMm2\n\t\tfibMMm2 = fibM - fibMMm1\n\t} else {\n\t\tresult = int64(i)\n\t\tbreak\n\t}\n}\nif result == -1 && fibMMm1 == 1 && offset+1 < n && nums[offset+1] == extra {\n\tresult = int64(offset + 1)\n}"),
    "ruby": ("n = nums.length\nresult = -1\nfib_mm2 = 0\nfib_mm1 = 1\nfib_m = fib_mm2 + fib_mm1\nwhile fib_m < n\n  fib_mm2 = fib_mm1\n  fib_mm1 = fib_m\n  fib_m = fib_mm2 + fib_mm1\nend\noffset = -1\nwhile fib_m > 1\n  i = [offset + fib_mm2, n - 1].min\n  i = 0 if i < 0\n  if nums[i] < extra\n    fib_m = fib_mm1\n    fib_mm1 = fib_mm2\n    fib_mm2 = fib_m - fib_mm1\n    offset = i\n  elsif nums[i] > extra\n    fib_m = fib_mm2\n    fib_mm1 = fib_mm1 - fib_mm2\n    fib_mm2 = fib_m - fib_mm1\n  else\n    result = i\n    break\n  end\nend\nif result == -1 && fib_mm1 == 1 && offset + 1 < n && nums[offset + 1] == extra\n  result = offset + 1\nend"),
    "kotlin": ("val n = nums.size\nvar result = -1L\nvar fibMMm2 = 0\nvar fibMMm1 = 1\nvar fibM = fibMMm2 + fibMMm1\nwhile (fibM < n) { fibMMm2 = fibMMm1; fibMMm1 = fibM; fibM = fibMMm2 + fibMMm1 }\nvar offset = -1\nwhile (fibM > 1) {\n    var i = minOf(offset + fibMMm2, n - 1)\n    if (i < 0) i = 0\n    if (nums[i] < extra) {\n        fibM = fibMMm1; fibMMm1 = fibMMm2; fibMMm2 = fibM - fibMMm1; offset = i\n    } else if (nums[i] > extra) {\n        fibM = fibMMm2; fibMMm1 -= fibMMm2; fibMMm2 = fibM - fibMMm1\n    } else {\n        result = i.toLong(); break\n    }\n}\nif (result == -1L && fibMMm1 == 1 && offset + 1 < n && nums[offset + 1] == extra) result = (offset + 1).toLong()"),
    "php": ("$n = count($nums);\n$result = -1;\n$fibMMm2 = 0; $fibMMm1 = 1; $fibM = $fibMMm2 + $fibMMm1;\nwhile ($fibM < $n) { $fibMMm2 = $fibMMm1; $fibMMm1 = $fibM; $fibM = $fibMMm2 + $fibMMm1; }\n$offset = -1;\nwhile ($fibM > 1) {\n    $i = min($offset + $fibMMm2, $n - 1);\n    if ($i < 0) { $i = 0; }\n    if ($nums[$i] < $extra) {\n        $fibM = $fibMMm1; $fibMMm1 = $fibMMm2; $fibMMm2 = $fibM - $fibMMm1; $offset = $i;\n    } elseif ($nums[$i] > $extra) {\n        $fibM = $fibMMm2; $fibMMm1 -= $fibMMm2; $fibMMm2 = $fibM - $fibMMm1;\n    } else {\n        $result = $i; break;\n    }\n}\nif ($result == -1 && $fibMMm1 == 1 && $offset + 1 < $n && $nums[$offset + 1] == $extra) { $result = $offset + 1; }"),
    "scala": ("val n = nums.length\nvar result: Long = -1L\nvar fibMMm2 = 0\nvar fibMMm1 = 1\nvar fibM = fibMMm2 + fibMMm1\nwhile (fibM < n) { fibMMm2 = fibMMm1; fibMMm1 = fibM; fibM = fibMMm2 + fibMMm1 }\nvar offset = -1\nvar found = false\nwhile (fibM > 1 && !found) {\n  var i = math.min(offset + fibMMm2, n - 1)\n  if (i < 0) i = 0\n  if (nums(i) < extra) {\n    fibM = fibMMm1; fibMMm1 = fibMMm2; fibMMm2 = fibM - fibMMm1; offset = i\n  } else if (nums(i) > extra) {\n    fibM = fibMMm2; fibMMm1 -= fibMMm2; fibMMm2 = fibM - fibMMm1\n  } else {\n    result = i.toLong; found = true\n  }\n}\nif (!found && fibMMm1 == 1 && offset + 1 < n && nums(offset + 1) == extra) result = (offset + 1).toLong"),
    "r": ("n <- length(nums)\nresult <- -1\nfibMMm2 <- 0; fibMMm1 <- 1; fibM <- fibMMm2 + fibMMm1\nwhile (fibM < n) { fibMMm2 <- fibMMm1; fibMMm1 <- fibM; fibM <- fibMMm2 + fibMMm1 }\noffset <- -1\nfound <- FALSE\nwhile (fibM > 1 && !found) {\n  i <- min(offset + fibMMm2, n - 1)\n  if (i < 0) i <- 0\n  if (nums[i + 1] < extra) {\n    fibM <- fibMMm1; fibMMm1 <- fibMMm2; fibMMm2 <- fibM - fibMMm1; offset <- i\n  } else if (nums[i + 1] > extra) {\n    fibM <- fibMMm2; fibMMm1 <- fibMMm1 - fibMMm2; fibMMm2 <- fibM - fibMMm1\n  } else {\n    result <- i; found <- TRUE\n  }\n}\nif (!found && fibMMm1 == 1 && offset + 1 < n && nums[offset + 2] == extra) result <- offset + 1"),
    "javascript": ("const n = nums.length;\nlet result = -1;\nlet fibMMm2 = 0, fibMMm1 = 1, fibM = fibMMm2 + fibMMm1;\nwhile (fibM < n) { fibMMm2 = fibMMm1; fibMMm1 = fibM; fibM = fibMMm2 + fibMMm1; }\nlet offset = -1;\nwhile (fibM > 1) {\n  let i = Math.min(offset + fibMMm2, n - 1);\n  if (i < 0) i = 0;\n  if (nums[i] < extra) { fibM = fibMMm1; fibMMm1 = fibMMm2; fibMMm2 = fibM - fibMMm1; offset = i; }\n  else if (nums[i] > extra) { fibM = fibMMm2; fibMMm1 = fibMMm1 - fibMMm2; fibMMm2 = fibM - fibMMm1; }\n  else { result = i; break; }\n}\nif (result === -1 && fibMMm1 === 1 && offset + 1 < n && nums[offset + 1] === extra) result = offset + 1;"),
    "typescript": ("const n = nums.length;\nlet result = -1;\nlet fibMMm2 = 0, fibMMm1 = 1, fibM = fibMMm2 + fibMMm1;\nwhile (fibM < n) { fibMMm2 = fibMMm1; fibMMm1 = fibM; fibM = fibMMm2 + fibMMm1; }\nlet offset = -1;\nwhile (fibM > 1) {\n  let i = Math.min(offset + fibMMm2, n - 1);\n  if (i < 0) i = 0;\n  if (nums[i] < extra) { fibM = fibMMm1; fibMMm1 = fibMMm2; fibMMm2 = fibM - fibMMm1; offset = i; }\n  else if (nums[i] > extra) { fibM = fibMMm2; fibMMm1 = fibMMm1 - fibMMm2; fibMMm2 = fibM - fibMMm1; }\n  else { result = i; break; }\n}\nif (result === -1 && fibMMm1 === 1 && offset + 1 < n && nums[offset + 1] === extra) result = offset + 1;"),
    "perl": ("my $n = scalar(@{$nums});\nmy $result = -1;\nmy $fibMMm2 = 0; my $fibMMm1 = 1; my $fibM = $fibMMm2 + $fibMMm1;\nwhile ($fibM < $n) { $fibMMm2 = $fibMMm1; $fibMMm1 = $fibM; $fibM = $fibMMm2 + $fibMMm1; }\nmy $offset = -1;\nwhile ($fibM > 1) {\n  my $i = $offset + $fibMMm2 < $n - 1 ? $offset + $fibMMm2 : $n - 1;\n  $i = 0 if $i < 0;\n  if ($nums->[$i] < $extra) { $fibM = $fibMMm1; $fibMMm1 = $fibMMm2; $fibMMm2 = $fibM - $fibMMm1; $offset = $i; }\n  elsif ($nums->[$i] > $extra) { $fibM = $fibMMm2; $fibMMm1 = $fibMMm1 - $fibMMm2; $fibMMm2 = $fibM - $fibMMm1; }\n  else { $result = $i; last; }\n}\nif ($result == -1 && $fibMMm1 == 1 && $offset + 1 < $n && $nums->[$offset + 1] == $extra) { $result = $offset + 1; }"),
    "java": ("int n = nums.length;\nint result = -1;\nint fibMMm2 = 0, fibMMm1 = 1, fibM = fibMMm2 + fibMMm1;\nwhile (fibM < n) { fibMMm2 = fibMMm1; fibMMm1 = fibM; fibM = fibMMm2 + fibMMm1; }\nint offset = -1;\nwhile (fibM > 1) {\n    int i = Math.min(offset + fibMMm2, n - 1);\n    if (i < 0) i = 0;\n    if (nums[i] < extra) { fibM = fibMMm1; fibMMm1 = fibMMm2; fibMMm2 = fibM - fibMMm1; offset = i; }\n    else if (nums[i] > extra) { fibM = fibMMm2; fibMMm1 -= fibMMm2; fibMMm2 = fibM - fibMMm1; }\n    else { result = i; break; }\n}\nif (result == -1 && fibMMm1 == 1 && offset + 1 < n && nums[offset + 1] == extra) result = offset + 1;"),
    "cpp": ("int n = (int) nums.size();\nint result = -1;\nint fibMMm2 = 0, fibMMm1 = 1, fibM = fibMMm2 + fibMMm1;\nwhile (fibM < n) { fibMMm2 = fibMMm1; fibMMm1 = fibM; fibM = fibMMm2 + fibMMm1; }\nint offset = -1;\nwhile (fibM > 1) {\n    int i = std::min(offset + fibMMm2, n - 1);\n    if (i < 0) i = 0;\n    if (nums[i] < extra) { fibM = fibMMm1; fibMMm1 = fibMMm2; fibMMm2 = fibM - fibMMm1; offset = i; }\n    else if (nums[i] > extra) { fibM = fibMMm2; fibMMm1 -= fibMMm2; fibMMm2 = fibM - fibMMm1; }\n    else { result = i; break; }\n}\nif (result == -1 && fibMMm1 == 1 && offset + 1 < n && nums[offset + 1] == extra) result = offset + 1;"),
    "csharp": ("int n = nums.Length;\nint result = -1;\nint fibMMm2 = 0, fibMMm1 = 1, fibM = fibMMm2 + fibMMm1;\nwhile (fibM < n) { fibMMm2 = fibMMm1; fibMMm1 = fibM; fibM = fibMMm2 + fibMMm1; }\nint offset = -1;\nwhile (fibM > 1) {\n    int i = System.Math.Min(offset + fibMMm2, n - 1);\n    if (i < 0) i = 0;\n    if (nums[i] < extra) { fibM = fibMMm1; fibMMm1 = fibMMm2; fibMMm2 = fibM - fibMMm1; offset = i; }\n    else if (nums[i] > extra) { fibM = fibMMm2; fibMMm1 -= fibMMm2; fibMMm2 = fibM - fibMMm1; }\n    else { result = i; break; }\n}\nif (result == -1 && fibMMm1 == 1 && offset + 1 < n && nums[offset + 1] == extra) result = offset + 1;"),
    "c": ("int result = -1;\nint fibMMm2 = 0, fibMMm1 = 1, fibM = fibMMm2 + fibMMm1;\nwhile (fibM < n) { fibMMm2 = fibMMm1; fibMMm1 = fibM; fibM = fibMMm2 + fibMMm1; }\nint offset = -1;\nwhile (fibM > 1) {\n    int i = (offset + fibMMm2 < n - 1) ? (offset + fibMMm2) : (n - 1);\n    if (i < 0) i = 0;\n    if (nums[i] < extra) { fibM = fibMMm1; fibMMm1 = fibMMm2; fibMMm2 = fibM - fibMMm1; offset = i; }\n    else if (nums[i] > extra) { fibM = fibMMm2; fibMMm1 -= fibMMm2; fibMMm2 = fibM - fibMMm1; }\n    else { result = i; break; }\n}\nif (result == -1 && fibMMm1 == 1 && offset + 1 < n && nums[offset + 1] == extra) result = offset + 1;"),
    "rust": ("let n = nums.len() as i32;\nlet mut result: i32 = -1;\nlet mut fib_mm2: i32 = 0;\nlet mut fib_mm1: i32 = 1;\nlet mut fib_m = fib_mm2 + fib_mm1;\nwhile fib_m < n { fib_mm2 = fib_mm1; fib_mm1 = fib_m; fib_m = fib_mm2 + fib_mm1; }\nlet mut offset: i32 = -1;\nwhile fib_m > 1 {\n    let mut i = std::cmp::min(offset + fib_mm2, n - 1);\n    if i < 0 { i = 0; }\n    if nums[i as usize] < extra { fib_m = fib_mm1; fib_mm1 = fib_mm2; fib_mm2 = fib_m - fib_mm1; offset = i; }\n    else if nums[i as usize] > extra { fib_m = fib_mm2; fib_mm1 -= fib_mm2; fib_mm2 = fib_m - fib_mm1; }\n    else { result = i; break; }\n}\nif result == -1 && fib_mm1 == 1 && offset + 1 < n && nums[(offset + 1) as usize] == extra { result = offset + 1; }"),
    "swift": ("let n = nums.count\nvar result = -1\nvar fibMMm2 = 0\nvar fibMMm1 = 1\nvar fibM = fibMMm2 + fibMMm1\nwhile fibM < n { fibMMm2 = fibMMm1; fibMMm1 = fibM; fibM = fibMMm2 + fibMMm1 }\nvar offset = -1\nwhile fibM > 1 {\n    var i = min(offset + fibMMm2, n - 1)\n    if i < 0 { i = 0 }\n    if nums[i] < extra { fibM = fibMMm1; fibMMm1 = fibMMm2; fibMMm2 = fibM - fibMMm1; offset = i }\n    else if nums[i] > extra { fibM = fibMMm2; fibMMm1 -= fibMMm2; fibMMm2 = fibM - fibMMm1 }\n    else { result = i; break }\n}\nif result == -1 && fibMMm1 == 1 && offset + 1 < n && nums[offset + 1] == extra { result = offset + 1 }"),
})

# ═════════════════════════════════════════════════════════════════════════
# ternary_search(nums, extra) -> divide sorted range into 3 parts each step
# ═════════════════════════════════════════════════════════════════════════
add("ternary-search", "arr1_int", "ternary_search", "int", {
    "go": ("lo, hi := 0, len(nums)-1\nresult := int64(-1)\nfor lo <= hi {\n\tthird := (hi - lo) / 3\n\tm1 := lo + third\n\tm2 := hi - third\n\tif nums[m1] == extra { result = int64(m1); break }\n\tif nums[m2] == extra { result = int64(m2); break }\n\tif extra < nums[m1] {\n\t\thi = m1 - 1\n\t} else if extra > nums[m2] {\n\t\tlo = m2 + 1\n\t} else {\n\t\tlo = m1 + 1\n\t\thi = m2 - 1\n\t}\n}"),
    "ruby": ("lo = 0\nhi = nums.length - 1\nresult = -1\nwhile lo <= hi\n  third = (hi - lo) / 3\n  m1 = lo + third\n  m2 = hi - third\n  if nums[m1] == extra\n    result = m1\n    break\n  elsif nums[m2] == extra\n    result = m2\n    break\n  elsif extra < nums[m1]\n    hi = m1 - 1\n  elsif extra > nums[m2]\n    lo = m2 + 1\n  else\n    lo = m1 + 1\n    hi = m2 - 1\n  end\nend"),
    "kotlin": ("var lo = 0\nvar hi = nums.size - 1\nvar result = -1L\nwhile (lo <= hi) {\n    val third = (hi - lo) / 3\n    val m1 = lo + third\n    val m2 = hi - third\n    if (nums[m1] == extra) { result = m1.toLong(); break }\n    if (nums[m2] == extra) { result = m2.toLong(); break }\n    if (extra < nums[m1]) hi = m1 - 1\n    else if (extra > nums[m2]) lo = m2 + 1\n    else { lo = m1 + 1; hi = m2 - 1 }\n}"),
    "php": ("$lo = 0; $hi = count($nums) - 1; $result = -1;\nwhile ($lo <= $hi) {\n    $third = intdiv($hi - $lo, 3);\n    $m1 = $lo + $third;\n    $m2 = $hi - $third;\n    if ($nums[$m1] == $extra) { $result = $m1; break; }\n    if ($nums[$m2] == $extra) { $result = $m2; break; }\n    if ($extra < $nums[$m1]) { $hi = $m1 - 1; }\n    elseif ($extra > $nums[$m2]) { $lo = $m2 + 1; }\n    else { $lo = $m1 + 1; $hi = $m2 - 1; }\n}"),
    "scala": ("var lo = 0\nvar hi = nums.length - 1\nvar result: Long = -1L\nvar found = false\nwhile (lo <= hi && !found) {\n  val third = (hi - lo) / 3\n  val m1 = lo + third\n  val m2 = hi - third\n  if (nums(m1) == extra) { result = m1.toLong; found = true }\n  else if (nums(m2) == extra) { result = m2.toLong; found = true }\n  else if (extra < nums(m1)) hi = m1 - 1\n  else if (extra > nums(m2)) lo = m2 + 1\n  else { lo = m1 + 1; hi = m2 - 1 }\n}"),
    "r": ("lo <- 1; hi <- length(nums); result <- -1\nwhile (lo <= hi) {\n  third <- (hi - lo) %/% 3\n  m1 <- lo + third\n  m2 <- hi - third\n  if (nums[m1] == extra) { result <- m1 - 1; break }\n  else if (nums[m2] == extra) { result <- m2 - 1; break }\n  else if (extra < nums[m1]) { hi <- m1 - 1 }\n  else if (extra > nums[m2]) { lo <- m2 + 1 }\n  else { lo <- m1 + 1; hi <- m2 - 1 }\n}"),
    "javascript": ("let lo = 0, hi = nums.length - 1;\nlet result = -1;\nwhile (lo <= hi) {\n  const third = Math.floor((hi - lo) / 3);\n  const m1 = lo + third, m2 = hi - third;\n  if (nums[m1] === extra) { result = m1; break; }\n  if (nums[m2] === extra) { result = m2; break; }\n  if (extra < nums[m1]) hi = m1 - 1;\n  else if (extra > nums[m2]) lo = m2 + 1;\n  else { lo = m1 + 1; hi = m2 - 1; }\n}"),
    "typescript": ("let lo = 0, hi = nums.length - 1;\nlet result = -1;\nwhile (lo <= hi) {\n  const third = Math.floor((hi - lo) / 3);\n  const m1 = lo + third, m2 = hi - third;\n  if (nums[m1] === extra) { result = m1; break; }\n  if (nums[m2] === extra) { result = m2; break; }\n  if (extra < nums[m1]) hi = m1 - 1;\n  else if (extra > nums[m2]) lo = m2 + 1;\n  else { lo = m1 + 1; hi = m2 - 1; }\n}"),
    "perl": ("my $lo = 0; my $hi = scalar(@{$nums}) - 1; my $result = -1;\nwhile ($lo <= $hi) {\n  my $third = int(($hi - $lo) / 3);\n  my $m1 = $lo + $third; my $m2 = $hi - $third;\n  if ($nums->[$m1] == $extra) { $result = $m1; last; }\n  if ($nums->[$m2] == $extra) { $result = $m2; last; }\n  if ($extra < $nums->[$m1]) { $hi = $m1 - 1; }\n  elsif ($extra > $nums->[$m2]) { $lo = $m2 + 1; }\n  else { $lo = $m1 + 1; $hi = $m2 - 1; }\n}"),
    "java": ("int lo = 0, hi = nums.length - 1;\nint result = -1;\nwhile (lo <= hi) {\n    int third = (hi - lo) / 3;\n    int m1 = lo + third, m2 = hi - third;\n    if (nums[m1] == extra) { result = m1; break; }\n    if (nums[m2] == extra) { result = m2; break; }\n    if (extra < nums[m1]) hi = m1 - 1;\n    else if (extra > nums[m2]) lo = m2 + 1;\n    else { lo = m1 + 1; hi = m2 - 1; }\n}"),
    "cpp": ("int lo = 0, hi = (int) nums.size() - 1;\nint result = -1;\nwhile (lo <= hi) {\n    int third = (hi - lo) / 3;\n    int m1 = lo + third, m2 = hi - third;\n    if (nums[m1] == extra) { result = m1; break; }\n    if (nums[m2] == extra) { result = m2; break; }\n    if (extra < nums[m1]) hi = m1 - 1;\n    else if (extra > nums[m2]) lo = m2 + 1;\n    else { lo = m1 + 1; hi = m2 - 1; }\n}"),
    "csharp": ("int lo = 0, hi = nums.Length - 1;\nint result = -1;\nwhile (lo <= hi) {\n    int third = (hi - lo) / 3;\n    int m1 = lo + third, m2 = hi - third;\n    if (nums[m1] == extra) { result = m1; break; }\n    if (nums[m2] == extra) { result = m2; break; }\n    if (extra < nums[m1]) hi = m1 - 1;\n    else if (extra > nums[m2]) lo = m2 + 1;\n    else { lo = m1 + 1; hi = m2 - 1; }\n}"),
    "c": ("int lo = 0, hi = n - 1;\nint result = -1;\nwhile (lo <= hi) {\n    int third = (hi - lo) / 3;\n    int m1 = lo + third, m2 = hi - third;\n    if (nums[m1] == extra) { result = m1; break; }\n    if (nums[m2] == extra) { result = m2; break; }\n    if (extra < nums[m1]) hi = m1 - 1;\n    else if (extra > nums[m2]) lo = m2 + 1;\n    else { lo = m1 + 1; hi = m2 - 1; }\n}"),
    "rust": ("let mut lo: i32 = 0;\nlet mut hi: i32 = nums.len() as i32 - 1;\nlet mut result: i32 = -1;\nwhile lo <= hi {\n    let third = (hi - lo) / 3;\n    let m1 = lo + third;\n    let m2 = hi - third;\n    if nums[m1 as usize] == extra { result = m1; break; }\n    if nums[m2 as usize] == extra { result = m2; break; }\n    if extra < nums[m1 as usize] { hi = m1 - 1; }\n    else if extra > nums[m2 as usize] { lo = m2 + 1; }\n    else { lo = m1 + 1; hi = m2 - 1; }\n}"),
    "swift": ("var lo = 0\nvar hi = nums.count - 1\nvar result = -1\nwhile lo <= hi {\n    let third = (hi - lo) / 3\n    let m1 = lo + third, m2 = hi - third\n    if nums[m1] == extra { result = m1; break }\n    if nums[m2] == extra { result = m2; break }\n    if extra < nums[m1] { hi = m1 - 1 }\n    else if extra > nums[m2] { lo = m2 + 1 }\n    else { lo = m1 + 1; hi = m2 - 1 }\n}"),
})

# ═════════════════════════════════════════════════════════════════════════
# search(nums, extra) -> index of extra in a ROTATED sorted array, or -1
# ═════════════════════════════════════════════════════════════════════════
add("rotated-binary-search", "arr1_int", "search", "int", {
    "go": ("lo, hi := 0, len(nums)-1\nresult := int64(-1)\nfor lo <= hi {\n\tmid := (lo + hi) / 2\n\tif nums[mid] == extra { result = int64(mid); break }\n\tif nums[lo] <= nums[mid] {\n\t\tif nums[lo] <= extra && extra < nums[mid] { hi = mid - 1 } else { lo = mid + 1 }\n\t} else {\n\t\tif nums[mid] < extra && extra <= nums[hi] { lo = mid + 1 } else { hi = mid - 1 }\n\t}\n}"),
    "ruby": ("lo = 0\nhi = nums.length - 1\nresult = -1\nwhile lo <= hi\n  mid = (lo + hi) / 2\n  if nums[mid] == extra\n    result = mid\n    break\n  end\n  if nums[lo] <= nums[mid]\n    if nums[lo] <= extra && extra < nums[mid]\n      hi = mid - 1\n    else\n      lo = mid + 1\n    end\n  else\n    if nums[mid] < extra && extra <= nums[hi]\n      lo = mid + 1\n    else\n      hi = mid - 1\n    end\n  end\nend"),
    "kotlin": ("var lo = 0\nvar hi = nums.size - 1\nvar result = -1L\nwhile (lo <= hi) {\n    val mid = (lo + hi) / 2\n    if (nums[mid] == extra) { result = mid.toLong(); break }\n    if (nums[lo] <= nums[mid]) {\n        if (nums[lo] <= extra && extra < nums[mid]) hi = mid - 1 else lo = mid + 1\n    } else {\n        if (nums[mid] < extra && extra <= nums[hi]) lo = mid + 1 else hi = mid - 1\n    }\n}"),
    "php": ("$lo = 0; $hi = count($nums) - 1; $result = -1;\nwhile ($lo <= $hi) {\n    $mid = intdiv($lo + $hi, 2);\n    if ($nums[$mid] == $extra) { $result = $mid; break; }\n    if ($nums[$lo] <= $nums[$mid]) {\n        if ($nums[$lo] <= $extra && $extra < $nums[$mid]) { $hi = $mid - 1; } else { $lo = $mid + 1; }\n    } else {\n        if ($nums[$mid] < $extra && $extra <= $nums[$hi]) { $lo = $mid + 1; } else { $hi = $mid - 1; }\n    }\n}"),
    "scala": ("var lo = 0\nvar hi = nums.length - 1\nvar result: Long = -1L\nvar found = false\nwhile (lo <= hi && !found) {\n  val mid = (lo + hi) / 2\n  if (nums(mid) == extra) { result = mid.toLong; found = true }\n  else if (nums(lo) <= nums(mid)) {\n    if (nums(lo) <= extra && extra < nums(mid)) hi = mid - 1 else lo = mid + 1\n  } else {\n    if (nums(mid) < extra && extra <= nums(hi)) lo = mid + 1 else hi = mid - 1\n  }\n}"),
    "r": ("lo <- 1; hi <- length(nums); result <- -1\nwhile (lo <= hi) {\n  mid <- (lo + hi) %/% 2\n  if (nums[mid] == extra) { result <- mid - 1; break }\n  if (nums[lo] <= nums[mid]) {\n    if (nums[lo] <= extra && extra < nums[mid]) { hi <- mid - 1 } else { lo <- mid + 1 }\n  } else {\n    if (nums[mid] < extra && extra <= nums[hi]) { lo <- mid + 1 } else { hi <- mid - 1 }\n  }\n}"),
    "javascript": ("let lo = 0, hi = nums.length - 1;\nlet result = -1;\nwhile (lo <= hi) {\n  const mid = (lo + hi) >> 1;\n  if (nums[mid] === extra) { result = mid; break; }\n  if (nums[lo] <= nums[mid]) {\n    if (nums[lo] <= extra && extra < nums[mid]) hi = mid - 1; else lo = mid + 1;\n  } else {\n    if (nums[mid] < extra && extra <= nums[hi]) lo = mid + 1; else hi = mid - 1;\n  }\n}"),
    "typescript": ("let lo = 0, hi = nums.length - 1;\nlet result = -1;\nwhile (lo <= hi) {\n  const mid = (lo + hi) >> 1;\n  if (nums[mid] === extra) { result = mid; break; }\n  if (nums[lo] <= nums[mid]) {\n    if (nums[lo] <= extra && extra < nums[mid]) hi = mid - 1; else lo = mid + 1;\n  } else {\n    if (nums[mid] < extra && extra <= nums[hi]) lo = mid + 1; else hi = mid - 1;\n  }\n}"),
    "perl": ("my $lo = 0; my $hi = scalar(@{$nums}) - 1; my $result = -1;\nwhile ($lo <= $hi) {\n  my $mid = int(($lo + $hi) / 2);\n  if ($nums->[$mid] == $extra) { $result = $mid; last; }\n  if ($nums->[$lo] <= $nums->[$mid]) {\n    if ($nums->[$lo] <= $extra && $extra < $nums->[$mid]) { $hi = $mid - 1; } else { $lo = $mid + 1; }\n  } else {\n    if ($nums->[$mid] < $extra && $extra <= $nums->[$hi]) { $lo = $mid + 1; } else { $hi = $mid - 1; }\n  }\n}"),
    "java": ("int lo = 0, hi = nums.length - 1;\nint result = -1;\nwhile (lo <= hi) {\n    int mid = (lo + hi) / 2;\n    if (nums[mid] == extra) { result = mid; break; }\n    if (nums[lo] <= nums[mid]) {\n        if (nums[lo] <= extra && extra < nums[mid]) hi = mid - 1; else lo = mid + 1;\n    } else {\n        if (nums[mid] < extra && extra <= nums[hi]) lo = mid + 1; else hi = mid - 1;\n    }\n}"),
    "cpp": ("int lo = 0, hi = (int) nums.size() - 1;\nint result = -1;\nwhile (lo <= hi) {\n    int mid = (lo + hi) / 2;\n    if (nums[mid] == extra) { result = mid; break; }\n    if (nums[lo] <= nums[mid]) {\n        if (nums[lo] <= extra && extra < nums[mid]) hi = mid - 1; else lo = mid + 1;\n    } else {\n        if (nums[mid] < extra && extra <= nums[hi]) lo = mid + 1; else hi = mid - 1;\n    }\n}"),
    "csharp": ("int lo = 0, hi = nums.Length - 1;\nint result = -1;\nwhile (lo <= hi) {\n    int mid = (lo + hi) / 2;\n    if (nums[mid] == extra) { result = mid; break; }\n    if (nums[lo] <= nums[mid]) {\n        if (nums[lo] <= extra && extra < nums[mid]) hi = mid - 1; else lo = mid + 1;\n    } else {\n        if (nums[mid] < extra && extra <= nums[hi]) lo = mid + 1; else hi = mid - 1;\n    }\n}"),
    "c": ("int lo = 0, hi = n - 1;\nint result = -1;\nwhile (lo <= hi) {\n    int mid = (lo + hi) / 2;\n    if (nums[mid] == extra) { result = mid; break; }\n    if (nums[lo] <= nums[mid]) {\n        if (nums[lo] <= extra && extra < nums[mid]) hi = mid - 1; else lo = mid + 1;\n    } else {\n        if (nums[mid] < extra && extra <= nums[hi]) lo = mid + 1; else hi = mid - 1;\n    }\n}"),
    "rust": ("let mut lo: i32 = 0;\nlet mut hi: i32 = nums.len() as i32 - 1;\nlet mut result: i32 = -1;\nwhile lo <= hi {\n    let mid = (lo + hi) / 2;\n    if nums[mid as usize] == extra { result = mid; break; }\n    if nums[lo as usize] <= nums[mid as usize] {\n        if nums[lo as usize] <= extra && extra < nums[mid as usize] { hi = mid - 1; } else { lo = mid + 1; }\n    } else {\n        if nums[mid as usize] < extra && extra <= nums[hi as usize] { lo = mid + 1; } else { hi = mid - 1; }\n    }\n}"),
    "swift": ("var lo = 0\nvar hi = nums.count - 1\nvar result = -1\nwhile lo <= hi {\n    let mid = (lo + hi) / 2\n    if nums[mid] == extra { result = mid; break }\n    if nums[lo] <= nums[mid] {\n        if nums[lo] <= extra && extra < nums[mid] { hi = mid - 1 } else { lo = mid + 1 }\n    } else {\n        if nums[mid] < extra && extra <= nums[hi] { lo = mid + 1 } else { hi = mid - 1 }\n    }\n}"),
})

# ═════════════════════════════════════════════════════════════════════════
# first_occurrence(nums, extra) -> leftmost index of extra, or -1
# ═════════════════════════════════════════════════════════════════════════
add("first-occurrence", "arr1_int", "first_occurrence", "int", {
    "go": "lo, hi := 0, len(nums)-1\nresult := int64(-1)\nfor lo <= hi {\n\tmid := (lo + hi) / 2\n\tif nums[mid] == extra { result = int64(mid); hi = mid - 1 } else if nums[mid] < extra { lo = mid + 1 } else { hi = mid - 1 }\n}",
    "ruby": "lo = 0\nhi = nums.length - 1\nresult = -1\nwhile lo <= hi\n  mid = (lo + hi) / 2\n  if nums[mid] == extra\n    result = mid\n    hi = mid - 1\n  elsif nums[mid] < extra\n    lo = mid + 1\n  else\n    hi = mid - 1\n  end\nend",
    "kotlin": "var lo = 0\nvar hi = nums.size - 1\nvar result = -1L\nwhile (lo <= hi) {\n    val mid = (lo + hi) / 2\n    if (nums[mid] == extra) { result = mid.toLong(); hi = mid - 1 }\n    else if (nums[mid] < extra) lo = mid + 1 else hi = mid - 1\n}",
    "php": "$lo = 0; $hi = count($nums) - 1; $result = -1;\nwhile ($lo <= $hi) {\n    $mid = intdiv($lo + $hi, 2);\n    if ($nums[$mid] == $extra) { $result = $mid; $hi = $mid - 1; }\n    elseif ($nums[$mid] < $extra) { $lo = $mid + 1; } else { $hi = $mid - 1; }\n}",
    "scala": "var lo = 0\nvar hi = nums.length - 1\nvar result: Long = -1L\nwhile (lo <= hi) {\n  val mid = (lo + hi) / 2\n  if (nums(mid) == extra) { result = mid.toLong; hi = mid - 1 }\n  else if (nums(mid) < extra) lo = mid + 1\n  else hi = mid - 1\n}",
    "r": "lo <- 1; hi <- length(nums); result <- -1\nwhile (lo <= hi) {\n  mid <- (lo + hi) %/% 2\n  if (nums[mid] == extra) { result <- mid - 1; hi <- mid - 1 }\n  else if (nums[mid] < extra) { lo <- mid + 1 } else { hi <- mid - 1 }\n}",
    "javascript": "let lo = 0, hi = nums.length - 1;\nlet result = -1;\nwhile (lo <= hi) {\n  const mid = (lo + hi) >> 1;\n  if (nums[mid] === extra) { result = mid; hi = mid - 1; }\n  else if (nums[mid] < extra) lo = mid + 1; else hi = mid - 1;\n}",
    "typescript": "let lo = 0, hi = nums.length - 1;\nlet result = -1;\nwhile (lo <= hi) {\n  const mid = (lo + hi) >> 1;\n  if (nums[mid] === extra) { result = mid; hi = mid - 1; }\n  else if (nums[mid] < extra) lo = mid + 1; else hi = mid - 1;\n}",
    "perl": "my $lo = 0; my $hi = scalar(@{$nums}) - 1; my $result = -1;\nwhile ($lo <= $hi) {\n  my $mid = int(($lo + $hi) / 2);\n  if ($nums->[$mid] == $extra) { $result = $mid; $hi = $mid - 1; }\n  elsif ($nums->[$mid] < $extra) { $lo = $mid + 1; } else { $hi = $mid - 1; }\n}",
    "java": "int lo = 0, hi = nums.length - 1;\nint result = -1;\nwhile (lo <= hi) {\n    int mid = (lo + hi) / 2;\n    if (nums[mid] == extra) { result = mid; hi = mid - 1; }\n    else if (nums[mid] < extra) lo = mid + 1; else hi = mid - 1;\n}",
    "cpp": "int lo = 0, hi = (int) nums.size() - 1;\nint result = -1;\nwhile (lo <= hi) {\n    int mid = (lo + hi) / 2;\n    if (nums[mid] == extra) { result = mid; hi = mid - 1; }\n    else if (nums[mid] < extra) lo = mid + 1; else hi = mid - 1;\n}",
    "csharp": "int lo = 0, hi = nums.Length - 1;\nint result = -1;\nwhile (lo <= hi) {\n    int mid = (lo + hi) / 2;\n    if (nums[mid] == extra) { result = mid; hi = mid - 1; }\n    else if (nums[mid] < extra) lo = mid + 1; else hi = mid - 1;\n}",
    "c": "int lo = 0, hi = n - 1;\nint result = -1;\nwhile (lo <= hi) {\n    int mid = (lo + hi) / 2;\n    if (nums[mid] == extra) { result = mid; hi = mid - 1; }\n    else if (nums[mid] < extra) lo = mid + 1; else hi = mid - 1;\n}",
    "rust": "let mut lo: i32 = 0;\nlet mut hi: i32 = nums.len() as i32 - 1;\nlet mut result: i32 = -1;\nwhile lo <= hi {\n    let mid = (lo + hi) / 2;\n    if nums[mid as usize] == extra { result = mid; hi = mid - 1; }\n    else if nums[mid as usize] < extra { lo = mid + 1; } else { hi = mid - 1; }\n}",
    "swift": "var lo = 0\nvar hi = nums.count - 1\nvar result = -1\nwhile lo <= hi {\n    let mid = (lo + hi) / 2\n    if nums[mid] == extra { result = mid; hi = mid - 1 }\n    else if nums[mid] < extra { lo = mid + 1 } else { hi = mid - 1 }\n}",
})

